css:
/* =====================================
   COST SHEET PRINT FORMAT
===================================== */

.cost-sheet {
    font-family: Arial, Helvetica, sans-serif;
    font-size: 11px;
    color: #000;
    padding: 5px;
}

/* =====================================
   HEADER
===================================== */

.header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 10px;
}

.company-section h2 {
    margin: 0;
    font-size: 20px;
    font-weight: 700;
    letter-spacing: 0.5px;
}

.company-section p {
    margin: 1px 0;
    font-size: 10px;
}

.title-section h3 {
    margin: 0;
    font-size: 18px;
    font-weight: bold;
    text-align: right;
}

/* =====================================
   SECTION TITLES
===================================== */

.section-title {
    margin-top: 12px;
    margin-bottom: 4px;
    padding-bottom: 3px;
    border-bottom: 1px solid #000;
    font-size: 12px;
    font-weight: bold;
}

/* =====================================
   INFO TABLE
===================================== */

.info-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 10px;
}

.info-table td {
    padding: 4px 5px;
    font-size: 11px;
    vertical-align: top;
}

/* =====================================
   MAIN TABLE
===================================== */

.main-table {
    width: 100%;
    border-collapse: collapse;
    border: 1px solid #000;
    margin-top: 5px;
}

.main-table th {
    background: #f2f2f2;
    border: 1px solid #000;
    padding: 5px;
    text-align: left;
    font-size: 11px;
    font-weight: bold;
}

.main-table td {
    border: 1px solid #000;
    padding: 5px;
    font-size: 11px;
    vertical-align: top;
}

/* =====================================
   SUMMARY TABLE
===================================== */

.summary-box {
    width: 45%;
    margin-left: auto;
    margin-top: 10px;
    margin-bottom: 15px;
}

.summary-box table {
    width: 100%;
    border-collapse: collapse;
    border: 1px solid #000;
}

.summary-box td {
    border: 1px solid #000;
    padding: 5px 8px;
    font-size: 11px;
}

.summary-box td:first-child {
    width: 70%;
    font-weight: bold;
}

.summary-box td:last-child {
    width: 30%;
    text-align: right;
}

/* =====================================
   COMPONENT TABLE
===================================== */

.component-table {
    width: 100%;
    border-collapse: collapse;
    border: 1px solid #000;
    margin-top: 5px;
}

.component-table th {
    background: #f2f2f2;
    border: 1px solid #000;
    padding: 5px;
    text-align: left;
    font-size: 11px;
    font-weight: bold;
}

.component-table td {
    border: 1px solid #000;
    padding: 5px;
    font-size: 11px;
    vertical-align: top;
}

/* =====================================
   FOOTER
===================================== */

.footer {
    margin-top: 20px;
    border-top: 1px solid #000;
    padding-top: 4px;
    font-size: 10px;
}

.page-no {
    float: right;
}

/* =====================================
   PRINT SETTINGS
===================================== */

@media print {

    .cost-sheet {
        padding: 0;
    }

    .footer {
        position: fixed;
        bottom: 0;
        width: 100%;
    }

    .main-table th,
    .main-table td,
    .component-table th,
    .component-table td,
    .summary-box td {
        padding: 4px;
    }
}
